import face_recognition
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import os
import pickle
import numpy as np
from sklearn.model_selection import train_test_split
from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score

app = Flask(__name__)

# Load employee photos and extract face encodings
employee_photos = []
for file in os.listdir('employee_photos'):
    image = face_recognition.load_image_file(os.path.join('employee_photos', file))
    encoding = face_recognition.face_encodings(image)[0]
    employee_photos.append(encoding)

# Train model on employee photos
X_train, X_test, y_train, y_test = train_test_split(employee_photos, [i for i in range(len(employee_photos))], test_size=0.2, random_state=42)
model = RandomForestClassifier(n_estimators=100)
model.fit(X_train, y_train)

# Save model to file
with open('model.pkl', 'wb') as f:
    pickle.dump(model, f)

# API endpoint to get confidence scores for all training classes
@app.route('/confidence_scores', methods=['POST'])
def get_confidence_scores():
    data = request.get_json()
    image = face_recognition.load_image_file(data['image_path'])
    encoding = face_recognition.face_encodings(image)[0]
    
    # Validate input and use secure platform APIs
    if not isinstance(encoding, np.ndarray) or len(encoding) != 128:
        return jsonify({'error': 'Invalid face encoding'}), 400
    
    predictions = model.predict_proba([encoding])
    confidence_scores = {i: score[1] for i, score in enumerate(predictions[0])}
    
    # Apply least privilege and explicit allowlists where relevant
    allowed_classes = [i for i in range(len(employee_photos))]
    confidence_scores = {class_id: score for class_id, score in confidence_scores.items() if class_id in allowed_classes}
    
    return jsonify(confidence_scores), 200

